class Stack:
    """
    A basic implementation of a stack data structure with push, pop, and peek operations.

    A stack is a Last-In-First-Out (LIFO) data structure where elements are added and removed from the top.

    Methods:
        push(item): Add an item to the top of the stack.
        pop(): Remove and return the top item from the stack.
        peek(): Return the top item without removing it.
        is_empty(): Check if the stack is empty.
        size(): Return the number of items in the stack.
    """

    def __init__(self):
        """Initialize an empty stack."""
        self._items = []

    def push(self, item):
        """Add an item to the top of the stack."""
        self._items.append(item)

    def pop(self):
        """Remove and return the top item from the stack.
        Returns: the top item, or None if stack is empty."""
        if self.is_empty():
            raise IndexError("pop from empty stack")
        return self._items.pop()

    def peek(self):
        """Return the top item without removing it.
        Returns: the top item, or None if stack is empty."""
        if self.is_empty():
            return None
        return self._items[-1]

    def is_empty(self):
        """Check if the stack is empty.
        Returns: True if stack is empty, False otherwise."""
        return len(self._items) == 0

    def size(self):
        """Return the number of items in the stack.
        Returns: integer representing the current size."""
        return len(self._items)

    # Optional: Provide a string representation for debugging
    def __str__(self):
        """Return a string representation of the stack (from top to bottom)."""
        if self.is_empty():
            return "Stack is empty"
        return f"Stack: {self._items}"

    # Optional: Enable iteration over the stack (from top to bottom)
    def __iter__(self):
        """Return an iterator that traverses the stack from top to bottom."""
        return reversed(self._items).__iter__()

    # Optional: Enable direct printing
    def __repr__(self):
        """Return a string representation suitable for debugging."""
        if self.is_empty():
            return "Stack([])"
        return f"Stack({self._items})"

